      totalProfit: entry.snapshot.holdings.reduce((sum, h) => sum + (h.profit || 0), 0)
    }));

    history.push({
      date: 'Now',
      assets: snapshot.totalAssets,
      totalProfit: snapshot.holdings.reduce((sum, h) => sum + (h.profit || 0), 0)
    });

    return history;
