                               <Legend />
                               <Line yAxisId="left" type="monotone" dataKey="assets" name="总资产" stroke="#3b82f6" strokeWidth={2} />
                               <Line yAxisId="right" type="monotone" dataKey="totalProfit" name="累计盈亏" stroke="#f59e0b" strokeWidth={2} />
                            </LineChart>
                         </ResponsiveContainer>
                      </div>
                   </div>
                </div>
             )}
           </div>
        </div>
