export const fetchStockDetailWithImage = async (base64Image: string, query: string, market: MarketType, apiKey: string, currentPrice?: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const now = new Date();
  const timeContext = now.toLocaleString('zh-CN');

  const prompt = `
    作为顶级 A 股量化交易专家，请对标的 "${query}" (市场: ${market}) 进行【全维度量化研判】。

    【核心任务 1：视觉对齐与价格核准】
    1. 你面前有一张该标的的实时行情截图。请强制提取图中的【最新现价】、【涨跌幅】、【分时/K线形态】。
    2. 如果用户提供了参考现价 (${currentPrice || '未提供'})，请结合截图验证其真实性。所有指标计算必须以此实时价为准。

    【核心任务 2：板块 Beta 与洗盘诊断 (核心进场/止损信号)】
    1. **板块联动性 (Beta)**: 联网搜索该标的所属板块今日的表现。分析该股是“领涨板块”、“跟随板块”还是“逆势下跌”。
    2. **洗盘 (Shakeout) 识别**: 
       - 观察截图中的成交量：如果是“股价下跌+成交量萎缩”，结合板块走势，判断是否为“良性洗盘”。
       - 如果是“放量大跌”且板块同步走弱，明确提示“恐慌派发”。
       - 如果是“缩量回调至支撑位”且板块指数稳定，给出【强烈入场/加仓】信号。
    3. **Alpha 走势**: 判断该股是否具备脱离板块的独立行情能力。

    【核心任务 3：量化指标与点位】
    - 结合图中 K 线位置，计算最新 BIAS (乖离率) 风险。
    - 给出极度精准的：支撑、压力、止盈、止损。

    [!!! 指令优先级 !!!]: 
    联网数据用于行业和公告背景；截图视觉数据用于价格、量能和形态。**截图数据拥有最高判定优先级**。

    请输出 Markdown 报告，必须包含“板块 Beta 与洗盘诊断”章节，并给出具体的【入场/加仓/减仓/离场】信号。
  `;

  const parts = [
    { text: prompt },
    { inlineData: { mimeType: 'image/jpeg', data: base64Image } }
  ];

  const response = await ai.models.generateContent({ 
    model: GEMINI_MODEL_PRIMARY, 
    contents: { parts },
    config: {
      tools: [{ googleSearch: {} }] 
    }
  });

  return { content: response.text || "", timestamp: Date.now(), modelUsed: ModelProvider.GEMINI_INTL, market };
};

